  (typeof ngDevMode === "undefined" || ngDevMode) && setClassMetadata(ReportRecipientsPickerComponent, [{
    type: Component,
    args: [{ selector: "app-report-recipients-picker", imports: [
      CommonModule,
      FormsModule,
      ButtonModule,
      ChipModule,
      SelectModule,
      PopoverModule
    ], template: `<div class="flex flex-col gap-2">
  <!-- Selected recipient chips -->
  @if (recipients().length > 0) {
    <div class="flex flex-wrap gap-1.5">
      @for (r of recipients(); track r.type + ':' + r.id) {
        <p-chip [removable]="true" (onRemove)="remove(r)" styleClass="text-xs">
          <i
            class="pi mr-1 text-[0.7rem]"
            [ngClass]="r.type === 'role' ? 'pi-users' : 'pi-user'"
          ></i>
          <span>{{ r.name }}</span>
          <span class="ml-1 text-[0.65rem] uppercase text-surface-400">{{
            r.type === 'role' ? 'Role' : 'User'
          }}</span>
        </p-chip>
      }
    </div>
  }

  <!-- Add recipient -->
  <div>
    <button
      type="button"
      class="inline-flex items-center gap-1.5 px-2.5 py-1 text-xs font-medium rounded-lg border border-surface-300 text-surface-700 bg-surface-0 cursor-pointer hover:bg-surface-50 transition-colors duration-150 disabled:opacity-50 disabled:cursor-not-allowed"
      [disabled]="atLimit()"
      (click)="toggleAdd($event)"
    >
      <i class="pi pi-plus text-[0.7rem]"></i>
      Add recipient
    </button>
    @if (atLimit()) {
      <span class="ml-2 text-[0.7rem] text-surface-400"
        >Maximum {{ maxRecipients }} recipients</span
      >
    }
  </div>

  <p-popover #addPopover>
    <div class="flex flex-col gap-2 w-64">
      <!-- Category toggle -->
      <div class="flex gap-1.5">
        <button
          type="button"
          class="flex-1 px-3 py-1 text-xs font-semibold rounded-full border transition-all duration-150 cursor-pointer"
          [ngClass]="
            category() === 'user'
              ? 'bg-primary border-primary text-white'
              : 'bg-transparent border-surface-300 text-surface-600 hover:bg-surface-50'
          "
          (click)="onCategoryChange('user')"
        >
          User
        </button>
        <button
          type="button"
          class="flex-1 px-3 py-1 text-xs font-semibold rounded-full border transition-all duration-150 cursor-pointer"
          [ngClass]="
            category() === 'role'
              ? 'bg-primary border-primary text-white'
              : 'bg-transparent border-surface-300 text-surface-600 hover:bg-surface-50'
          "
          (click)="onCategoryChange('role')"
        >
          User Role
        </button>
      </div>

      <!-- Searchable select -->
      <p-select
        appendTo="body"
        styleClass="w-full"
        [options]="currentOptions()"
        optionLabel="label"
        optionValue="value"
        [filter]="true"
        filterBy="label"
        [showClear]="true"
        [loading]="optionsLoading()"
        [ngModel]="selectedId()"
        (ngModelChange)="selectedId.set($event)"
        [placeholder]="
          category() === 'user' ? 'Select a user' : 'Select a user role'
        "
        [emptyMessage]="
          optionsLoading()
            ? 'Loading...'
            : category() === 'user'
              ? 'No users found'
              : 'No roles found'
        "
        emptyFilterMessage="No matches"
      />

      <p-button
        label="Add"
        icon="pi pi-check"
        size="small"
        [disabled]="!selectedId() || atLimit()"
        (onClick)="onAdd()"
      />
    </div>
  </p-popover>
</div>
` }]
  }], () => [], { ownerId: [{ type: Input, args: [{ isSignal: true, alias: "ownerId", required: false }] }], recipientsChange: [{ type: Output, args: ["recipientsChange"] }], addPopover: [{ type: ViewChild, args: ["addPopover", { isSignal: true }] }] });
