(() => {
  (typeof ngDevMode === "undefined" || ngDevMode) && setClassMetadata(InlineReportTypeSelectorComponent, [{
    type: Component,
    args: [{ selector: "app-inline-report-type-selector", imports: [
      CommonModule,
      ButtonModule,
      InlineGeofenceFilterComponent,
      InlineEventTypeFilterComponent,
      InlineAlertTypeFilterComponent,
      InlineSpeedingFilterComponent,
      InlineIdlingFilterComponent,
      InlineUtilisationFilterComponent,
      InlineStoppingFilterComponent,
      InlineAdditionalColumnsComponent
    ], template: `<div
  class="flex flex-col gap-3 p-3 rounded-xl border border-default shadow-sm bg-contentBg"
>
  <!-- Header with Actions -->
  <div class="flex items-center justify-between gap-2">
    <span class="text-sm font-semibold text-color"
      >Select report types to generate:</span
    >
    <div class="flex gap-1.5">
      @if (!allSelected()) {
        <button
          type="button"
          class="px-2.5 py-1 text-xs font-medium bg-transparent border border-default rounded text-color cursor-pointer hover:bg-hover transition-colors duration-150"
          (click)="selectAll()"
        >
          Select All
        </button>
      } @else {
        <button
          type="button"
          class="px-2.5 py-1 text-xs font-medium bg-transparent border border-default rounded text-color cursor-pointer hover:bg-hover transition-colors duration-150"
          (click)="clearAll()"
        >
          Clear All
        </button>
      }
    </div>
  </div>

  <!-- Report Type Cards -->
  <div
    class="grid grid-cols-3 gap-2 max-[500px]:grid-cols-2 max-[320px]:grid-cols-1"
  >
    @for (type of reportTypes; track type.report_type) {
      <button
        type="button"
        class="relative flex flex-col items-start gap-1 p-2.5 rounded-lg border-2 text-left cursor-pointer transition-all duration-150"
        [ngClass]="
          isSelected(type.report_type)
            ? 'bg-primary/10 border-primary'
            : 'bg-contentBg border-default hover:bg-hover hover:border-primary/50'
        "
        (click)="toggleType(type.report_type)"
      >
        <div class="absolute top-1.5 right-1.5">
          <input
            type="checkbox"
            class="w-3.5 h-3.5 cursor-pointer accent-primary"
            [checked]="isSelected(type.report_type)"
            (click)="$event.stopPropagation()"
            (change)="toggleType(type.report_type)"
          />
        </div>
        <i
          class="pi {{ type.icon }} text-lg mb-0.5"
          [ngClass]="
            isSelected(type.report_type)
              ? 'text-primary'
              : 'text-color-secondary'
          "
        ></i>
        <span
          class="text-xs font-semibold pr-4"
          [ngClass]="
            isSelected(type.report_type) ? 'text-primary' : 'text-color'
          "
          >{{ type.display_name }}</span
        >
        <span class="text-[0.625rem] leading-snug text-color-secondary">{{
          type.description
        }}</span>
      </button>
    }
  </div>

  <!-- Geofence Filter (only when the user ticked Geofence) -->
  @if (isGeofenceSelected()) {
    <div class="pt-1 border-t border-default">
      <app-inline-geofence-filter
        [ownerId]="ownerId()"
        (filterChanged)="geofenceFilter.set($event)"
      />
    </div>
  }

  <!-- Event Type Filter (only when the user ticked Events) -->
  @if (isEventsSelected()) {
    <div class="geofence-filter-section">
      <app-inline-event-type-filter
        (filterChanged)="eventTypeFilter.set($event)"
      />
    </div>
  }

  <!-- Alert Filter (only when the user ticked Alerts) -->
  @if (isAlertsSelected()) {
    <div class="geofence-filter-section">
      <app-inline-alert-type-filter
        (filterChanged)="alertTypeFilter.set($event)"
      />
    </div>
  }

  <!-- Over Speeding Filter (only when the user ticked Speeding) -->
  @if (isSpeedingSelected()) {
    <div class="geofence-filter-section">
      <app-inline-speeding-filter
        (filterChanged)="speedingFilter.set($event)"
      />
    </div>
  }

  <!-- Excessive Idling Filter (only when the user ticked Idling) -->
  @if (isIdlingSelected()) {
    <div class="geofence-filter-section">
      <app-inline-idling-filter (filterChanged)="idlingFilter.set($event)" />
    </div>
  }

  <!-- Utilization Filter (only when the user ticked Daily Utilisation) -->
  @if (isDailyUtilisationSelected()) {
    <div class="geofence-filter-section">
      <app-inline-utilisation-filter
        (filterChanged)="utilisationFilter.set($event)"
      />
    </div>
  }

  <!-- Stopping Filter (only when the user ticked Stopping) -->
  @if (isStoppingSelected()) {
    <div class="geofence-filter-section">
      <app-inline-stopping-filter
        (filterChanged)="stoppingFilter.set($event)"
      />
    </div>
  }

  <!-- Additional Columns (only when the user ticked Trip Summary) -->
  @if (isDailySummarySelected()) {
    <div class="pt-1 border-t border-default">
      <app-inline-additional-columns
        [reportType]="'trip_history_daily_summary'"
        [ownerId]="ownerId()"
        (selectionChanged)="additionalColumns.set($event)"
      />
    </div>
  }

  <!-- Selection Summary & Confirm -->
  <div
    class="flex items-center justify-between gap-3 px-3 py-2 rounded border bg-primary/10 border-primary"
  >
    <div
      class="flex items-center gap-2 text-[0.8125rem] font-medium text-primary"
    >
      <i class="pi pi-file-excel"></i>
      @if (canConfirm()) {
        <span
          >{{ selectedCount() }} report type{{
            selectedCount() === 1 ? '' : 's'
          }}
          selected</span
        >
      } @else {
        <span>Select report types to generate</span>
      }
    </div>
    <p-button
      label="Continue"
      icon="pi pi-arrow-right"
      iconPos="right"
      [disabled]="!canConfirm()"
      (onClick)="onConfirm()"
      size="small"
    />
  </div>
</div>
`, styles: ["/* src/app/features/development/components/analytical-report/chat/components/inline-report-type-selector/inline-report-type-selector.component.scss */\n:host {\n  display: block;\n}\n/*# sourceMappingURL=inline-report-type-selector.component.css.map */\n"] }]
  }], null, { ownerId: [{ type: Input, args: [{ isSignal: true, alias: "ownerId", required: false }] }], reportTypesConfirmed: [{ type: Output, args: ["reportTypesConfirmed"] }] });
})();
