// src/app/features/development/components/analytical-report/chat/utils/confidence.utils.ts
function getConfidenceDisplay(confidence) {
  const level = confidence >= 90 ? "high" : confidence >= 70 ? "medium" : confidence >= 50 ? "building" : "low";
  const label = level === "high" ? "Ready to generate" : level === "medium" ? "Almost ready" : level === "building" ? "Continue refining" : "Keep chatting...";
  const barClass = level === "high" ? "bg-green-500" : level === "medium" ? "bg-yellow-400" : level === "building" ? "bg-primary" : "bg-yellow-400";
  const textClass = level === "high" ? "text-green-600" : level === "medium" ? "text-yellow-600" : level === "building" ? "text-primary" : "text-yellow-600";
  return { level, label, barClass, textClass };
}

