  onOpenConfigDrawer() {
    this.facade.openConfigDrawer("now");
  }
  onNewSchedule() {
    this.facade.openConfigDrawer("schedule");
  }
  async onDrawerGenerateNow(result) {
    await this.facade.handleDrawerGenerateNow(result);
  }
  async onFooterGenerateAnalyticalReview() {
    await this.facade.handleFooterGenerateAnalyticalReview();
  }
  onCollapseViewer() {
    this.facade.setViewerCollapsed(true);
  }
  onExpandViewer() {
    this.facade.setViewerCollapsed(false);
  }
  onReportConfigSelected(config) {
    this.facade.handleReportConfigSelected(config);
  }
  onNewReport() {
    this.facade.resetAll();
  }
  // ── Sidebar event handlers ────────────────────────────────────────────────
  onShowReports() {
    this.facade.handleShowReports();
  }
  onShowAnalyticalReport() {
    void this.facade.showLatestAnalyticalReport();
  }
  onNewConversation() {
    this.closeSidebarOverlay();
    this.facade.startNewConversation();
  }
